<?php
 namespace WPAICG\Chat\Storage\ReaderMethods; use WPAICG\Chat\Storage\ConversationReader; use WPAICG\Core\AIPKit_Payload_Sanitizer; if (!defined('ABSPATH')) { exit; } function sanitize_message_payload_fields_for_history(array $message): array { foreach (['request_payload', 'response_data'] as $field_key) { if (array_key_exists($field_key, $message)) { $message[$field_key] = AIPKit_Payload_Sanitizer::sanitize_payload_if_array($message[$field_key]); } } return $message; } function get_conversation_thread_history_logic( ConversationReader $readerInstance, ?int $user_id, ?string $session_id, int $bot_id, string $conversation_uuid ): array { if (empty($bot_id) || empty($conversation_uuid) || (!$user_id && empty($session_id))) { return []; } $wpdb = $readerInstance->get_wpdb(); $table_name = $readerInstance->get_table_name(); $cache_key = 'conv_history_' . $conversation_uuid; $cache_group = 'aipkit_chat_logs'; $messages_json = wp_cache_get($cache_key, $cache_group); if (false === $messages_json) { $where_sql = "bot_id = %d AND conversation_uuid = %s AND "; $params = [$bot_id, $conversation_uuid]; if ($user_id) { $where_sql .= "user_id = %d"; $params[] = $user_id; } else { $where_sql .= "(user_id IS NULL AND session_id = %s AND is_guest = 1)"; $params[] = $session_id; } $messages_json = $wpdb->get_var($wpdb->prepare("SELECT messages FROM {$table_name} WHERE {$where_sql} LIMIT 1", $params)); wp_cache_set($cache_key, $messages_json, $cache_group, HOUR_IN_SECONDS); } if (empty($messages_json)) { return []; } $conversation_data = json_decode($messages_json, true); $messages_array = null; if (is_array($conversation_data) && isset($conversation_data['parent_id']) && isset($conversation_data['messages']) && is_array($conversation_data['messages'])) { $messages_array = $conversation_data['messages']; } elseif (is_array($conversation_data)) { $messages_array = $conversation_data; } else { return []; } $filtered_messages = []; foreach ($messages_array as $msg) { if (isset($msg['role']) && $msg['role'] === 'system' && isset($msg['event_sub_type']) && $msg['event_sub_type'] === 'trigger_log') { continue; } if (isset($msg['timestamp'])) { $msg['timestamp'] = (int)$msg['timestamp']; } if (!isset($msg['message_id'])) { $msg['message_id'] = generate_message_id_logic(); } $msg = sanitize_message_payload_fields_for_history($msg); $filtered_messages[] = $msg; } return $filtered_messages; } 